      "parcel_id": "APN-778-002-11",
      "current_status": "UNDER_REVIEW",
      "variance_type": "Rear Setback Reduction",
      "requested_reduction": "12-foot"
    }
  },
  "get_parcel_compliance_history": {
    "description": "Retrieves the code enforcement history for a specific parcel, including open violations and unpermitted structures.",
    "parameters": {
      "type": "object",
      "properties": {
